{
  "exclude": [
    "node_modules",
    "dist",
    "**/*.spec.ts"   // exclude test files from production build
  ]
}

{
  "compilerOptions": {
    "rootDir": "./src",   // input root — preserves directory structure in output
    "outDir": "./dist"    // compiled .js files land here
  }
}
// src/app/component.ts → dist/app/component.js

{
  "compilerOptions": {
    "strict": true   // equivalent to enabling all six options below
  }
}

{
  "compilerOptions": {
    "strict": true,
    "noUnusedLocals": true,       // error on variables declared but never read
    "noUnusedParameters": true,   // error on function parameters never used
    "noImplicitReturns": true,    // all code paths must return a value
    "noFallthroughCasesInSwitch": true, // switch cases must break or return
    "exactOptionalPropertyTypes": true  // undefined ≠ absent optional property
  }
}

// Before paths:
import { UserService } from '../../../core/services/user.service';

// After paths:
import { UserService } from '@app/core/services/user.service';

{
  // tsconfig.json (root — shared settings)
  "compilerOptions": {
    "target": "ES2022",
    "module": "ES2022",
    "moduleResolution": "bundler",
    "strict": true,
    "experimentalDecorators": true,
    "emitDecoratorMetadata": false,
    "useDefineForClassFields": false,
    "lib": ["ES2022", "DOM", "DOM.Iterable"]
  }
}

{
  // tsconfig.app.json (production build)
  "extends": "./tsconfig.json",
  "compilerOptions": {
    "outDir": "./out-tsc/app",
    "types": []          // no @types in the app build (keeps bundle clean)
  },
  "files": [
    "src/main.ts"
  ],
  "include": [
    "src/**/*.d.ts"
  ]
}

{
  "compilerOptions": {
    // Only include these @types packages — all others are excluded
    "types": ["node", "jest"],

    // OR: look for types in a custom directory (rarely needed)
    "typeRoots": ["./node_modules/@types", "./typings"]
  }
}

{
  "compilerOptions": {
    // experimentalDecorators: not set (defaults to false)
    "useDefineForClassFields": true   // standard behavior
  }
}
